-- Prompt 23 cross-gym isolation, audited reports/moderation and hidden-safe counts.
begin;
set local role authenticated;select set_config('request.jwt.claim.role','authenticated',true);select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000004',true);
do $$begin begin perform public.create_community_post('30000000-0000-4000-8000-000000000001','Before consent','No','');raise exception 'Posted without guidelines';exception when insufficient_privilege then null;end;perform public.accept_community_guidelines('30000000-0000-4000-8000-000000000001');end$$;
do $$declare post_id uuid;comment_id uuid;begin post_id:=public.create_community_post('30000000-0000-4000-8000-000000000001','Test post','Visible community body',null);comment_id:=public.create_community_comment('30000000-0000-4000-8000-000000000001',post_id,'Visible comment');perform public.toggle_community_reaction('30000000-0000-4000-8000-000000000001',post_id,'support');perform set_config('test.community_post',post_id::text,true);perform set_config('test.community_comment',comment_id::text,true);begin update public.community_posts set moderation_status='hidden'where id=post_id;raise exception 'Author directly changed moderation';exception when insufficient_privilege then null;end;begin perform public.create_community_post('30000000-0000-4000-8000-000000000099','Cross gym','No',null);raise exception 'Cross-gym post succeeded';exception when insufficient_privilege then null;end;end$$;
select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000003',true);
select public.report_community_content('30000000-0000-4000-8000-000000000001','post',current_setting('test.community_post')::uuid,'Safety concern');
select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000001',true);
select public.moderate_community_post('30000000-0000-4000-8000-000000000001',current_setting('test.community_post')::uuid,'hidden',true,'Safety review',false);
select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000003',true);
do $$begin if exists(select 1 from public.community_posts where id=current_setting('test.community_post')::uuid)then raise exception 'Hidden post leaked';end if;if exists(select 1 from public.comments where id=current_setting('test.community_comment')::uuid)then raise exception 'Comment on hidden post leaked';end if;if exists(select 1 from public.reactions where post_id=current_setting('test.community_post')::uuid)then raise exception 'Hidden reaction count leaked';end if;end$$;
set local role service_role;do $$begin if not exists(select 1 from public.audit_logs where action='community.content.reported'and target_id=current_setting('test.community_post')::uuid)or not exists(select 1 from public.audit_logs where action='community.post.moderated'and target_id=current_setting('test.community_post')::uuid)then raise exception 'Report or moderation audit missing';end if;end$$;
rollback;
